patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 9f034aba874a..66d4f0594661 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -3344,6 +3344,18 @@ Instruction *InstCombinerImpl::foldICmpBinOpEqualityWithConstant(
         Neg->takeName(BO);
         return new ICmpInst(Pred, BOp0, Neg);
       }
+    } else if (C.isOne() && BO->hasOneUse() && BO->hasNoUnsignedWrap() &&
+               BO->hasNoSignedWrap()) {
+      // Fold icmp eq/ne (add nuw nsw (zext i1 X), (zext i1 Y)), 1 to xor X, Y
+      // or its inverse.
+      Value *X, *Y;
+      if (match(BOp0, m_ZExt(m_Value(X))) && match(BOp1, m_ZExt(m_Value(Y))) &&
+          X->getType()->isIntOrIntVectorTy(1) && Y->getType()->isIntOrIntVectorTy(1)) {
+        Value *Xor = Builder.CreateXor(X, Y);
+        if (Pred == ICmpInst::ICMP_EQ)
+          return replaceInstUsesWith(Cmp, Xor);
+        return replaceInstUsesWith(Cmp, Builder.CreateNot(Xor));
+      }
     }
     break;
   }

